import{_ as s,o as e,c as a,aw as o}from"./chunks/framework.Dq2onT5h.js";const n=JSON.parse('{"title":"P2P","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"P2P | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"learn/specs/p2p.md","filePath":"learn/specs/p2p.md","lastUpdated":1754470767000}');const t=s({name:"learn/specs/p2p.md"},[["render",function(s,n,t,p,l,r){return e(),a("div",null,[...n[0]||(n[0]=[o('<h1 id="p2p" tabindex="-1">P2P <a class="header-anchor" href="#p2p" aria-label="Permalink to &quot;P2P&quot;">​</a></h1><p>Every node (both full and light) runs a P2P client using <a href="https://github.com/libp2p/go-libp2p" target="_blank" rel="noreferrer">go-libp2p</a> P2P networking stack for gossiping transactions in the chain&#39;s P2P network. The same P2P client is also used by the header and block sync services for gossiping headers and blocks.</p><p>Following parameters are required for creating a new instance of a P2P client:</p><ul><li>P2PConfig (described below)</li><li><a href="https://github.com/libp2p/go-libp2p" target="_blank" rel="noreferrer">go-libp2p</a> private key used to create a libp2p connection and join the p2p network.</li><li>chainID: identifier used as namespace within the p2p network for peer discovery. The namespace acts as a sub network in the p2p network, where peer connections are limited to the same namespace.</li><li>datastore: an instance of <a href="https://github.com/ipfs/go-datastore" target="_blank" rel="noreferrer">go-datastore</a> used for creating a connection gator and stores blocked and allowed peers.</li><li>logger</li></ul><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;">// P2PConfig stores configuration related to peer-to-peer networking.</span></span>\n<span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> P2PConfig</span><span style="color:#B8A6FF;"> struct</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#DBD7CA;">\tListenAddress </span><span style="color:#B8A6FF;">string</span><span style="color:#A0A0A0;"> // Address to listen for incoming connections</span></span>\n<span class="line"><span style="color:#DBD7CA;">\tSeeds         </span><span style="color:#B8A6FF;">string</span><span style="color:#A0A0A0;"> // Comma separated list of seed nodes to connect to</span></span>\n<span class="line"><span style="color:#DBD7CA;">\tBlockedPeers  </span><span style="color:#B8A6FF;">string</span><span style="color:#A0A0A0;"> // Comma separated list of nodes to ignore</span></span>\n<span class="line"><span style="color:#DBD7CA;">\tAllowedPeers  </span><span style="color:#B8A6FF;">string</span><span style="color:#A0A0A0;"> // Comma separated list of nodes to whitelist</span></span>\n<span class="line"><span style="color:#767676;">}</span></span></code></pre></div><p>A P2P client also instantiates a <a href="https://github.com/libp2p/go-libp2p/tree/master/p2p/net/conngater" target="_blank" rel="noreferrer">connection gator</a> to block and allow peers specified in the <code>P2PConfig</code>.</p><p>It also sets up a gossiper using the gossip topic <code>&lt;chainID&gt;+&lt;txTopicSuffix&gt;</code> (<code>txTopicSuffix</code> is defined in <a href="https://github.com/evstack/ev-node/blob/main/pkg/p2p/client.go" target="_blank" rel="noreferrer">p2p/client.go</a>), a Distributed Hash Table (DHT) using the <code>Seeds</code> defined in the <code>P2PConfig</code> and peer discovery using go-libp2p&#39;s <code>discovery.RoutingDiscovery</code>.</p><p>A P2P client provides an interface <code>SetTxValidator(p2p.GossipValidator)</code> for specifying a gossip validator which can define how to handle the incoming <code>GossipMessage</code> in the P2P network. The <code>GossipMessage</code> represents message gossiped via P2P network (e.g. transaction, Block etc).</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;">// GossipValidator is a callback function type.</span></span>\n<span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> GossipValidator</span><span style="color:#B8A6FF;"> func</span><span style="color:#767676;">(</span><span style="color:#888888;">*</span><span style="color:#CDA4EB;">GossipMessage</span><span style="color:#767676;">)</span><span style="color:#B8A6FF;"> bool</span></span></code></pre></div><p>The full nodes define a transaction validator (shown below) as gossip validator for processing the gossiped transactions to add to the mempool, whereas light nodes simply pass a dummy validator as light nodes do not process gossiped transactions.</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;">// newTxValidator creates a pubsub validator that uses the node&#39;s mempool to check the</span></span>\n<span class="line"><span style="color:#A0A0A0;">// transaction. If the transaction is valid, then it is added to the mempool</span></span>\n<span class="line"><span style="color:#B8A6FF;">func</span><span style="color:#767676;"> (</span><span style="color:#DBD7CA;">n </span><span style="color:#888888;">*</span><span style="color:#CDA4EB;">FullNode</span><span style="color:#767676;">)</span><span style="color:#94EEFF;"> newTxValidator</span><span style="color:#767676;">()</span><span style="color:#CDA4EB;"> p2p</span><span style="color:#767676;">.</span><span style="color:#CDA4EB;">GossipValidator</span><span style="color:#767676;"> {</span></span></code></pre></div><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;">// Dummy validator that always returns a callback function with boolean `false`</span></span>\n<span class="line"><span style="color:#B8A6FF;">func</span><span style="color:#767676;"> (</span><span style="color:#DBD7CA;">ln </span><span style="color:#888888;">*</span><span style="color:#CDA4EB;">LightNode</span><span style="color:#767676;">)</span><span style="color:#94EEFF;"> falseValidator</span><span style="color:#767676;">()</span><span style="color:#CDA4EB;"> p2p</span><span style="color:#767676;">.</span><span style="color:#CDA4EB;">GossipValidator</span><span style="color:#767676;"> {</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><p>[1] <a href="https://github.com/evstack/ev-node/blob/main/pkg/p2p/client.go" target="_blank" rel="noreferrer">client.go</a></p><p>[2] <a href="https://github.com/ipfs/go-datastore" target="_blank" rel="noreferrer">go-datastore</a></p><p>[3] <a href="https://github.com/libp2p/go-libp2p" target="_blank" rel="noreferrer">go-libp2p</a></p><p>[4] <a href="https://github.com/libp2p/go-libp2p/tree/master/p2p/net/conngater" target="_blank" rel="noreferrer">conngater</a></p>',17)])])}]]);export{n as __pageData,t as default};
